# -*- coding: utf-8 -*-
# 自动生成的数据库种子数据
import os, base64

SEED_countdown = ''

SEED_gpa = ''


def _has_data(db_path):
    try:
        import sqlite3
        conn = sqlite3.connect(db_path)
        for t in [t[0] for t in conn.execute("SELECT name FROM sqlite_master WHERE type='table' AND name NOT LIKE 'sqlite_%'").fetchall()]:
            if conn.execute(f"SELECT COUNT(*) FROM [{t}]").fetchone()[0] > 0:
                conn.close()
                return True
        conn.close()
        return False
    except Exception:
        return False

def restore_seed_dbs(base_dir):
    """恢复种子数据库到目标目录（仅当目标文件无数据时）"""
    seeds = {
        os.path.join(base_dir, '倒计时/countdown.db'): SEED_countdown,
        os.path.join(base_dir, '绩点/gpa.db'): SEED_gpa,
    }
    for path, data in seeds.items():
        if os.path.exists(path) and _has_data(path):
            continue  # 已有数据，不覆盖
        os.makedirs(os.path.dirname(path), exist_ok=True)
        with open(path, "wb") as f:
            f.write(base64.b64decode(data))